                      <div style={{height:"100%",background:`linear-gradient(90deg,${C.a3},${C.accent})`,borderRadius:4,transition:"width 0.3s",width:scanQueue.length>0?`${Math.round(((scanQueue[0]?.index||0)/((scanQueue[0]?.total||1)))*100)}%`:"70%"}}/>
